#include<bits/stdc++.h>
using namespace std;
int n, a[5005];
int dp[5005];
long long cnt[5005];

int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) cin >> a[i];
	for (int i = 1; i <= n; i++) {
		dp[i] = 1;
		cnt[i] = 1;
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j < i; j++) {
			if (a[j] > a[i]) {
				if (dp[j] + 1 > dp[i]) {
					dp[i] = dp[j] + 1;
					cnt[i] = cnt[j];
				} else if (dp[j] + 1 == dp[i]) {
					cnt[i] += cnt[j];
				}
			}
		}
		for (int j = 1; j < i; j++) {
			if (a[j] == a[i] && dp[j] == dp[i]) {
				cnt[j] = 0;
			}
		}
	}
	int maxx = 0;
	for (int i = 1; i <= n; i++) maxx = max(maxx, dp[i]);
	long long ans = 0;
	for (int i = 1; i <= n; i++) {
		if (dp[i] == maxx) ans += cnt[i];
	}
	cout << maxx << " " << ans << endl;
	return 0;
}
